const input = $input.first().json;
let texts = [];

// Support single text or array of texts
if (input.body && input.body.texts && Array.isArray(input.body.texts)) {
  texts = input.body.texts.slice(0, 10); // Max 10 texts per batch
} else if (input.body && input.body.text) {
  texts = [input.body.text];
} else {
  return [{ json: { error: 'Provide { "text": "..." } or { "texts": ["...", "..."] } in the request body', valid: false } }];
}

if (texts.length === 0 || texts.some(t => !t || t.length < 2)) {
  return [{ json: { error: 'Each text must be at least 2 characters long', valid: false } }];
}

return [{ json: { texts, count: texts.length, valid: true } }];

const ollamaResponse = $input.first().json;
let responseText;

try {
  const parsed = typeof ollamaResponse.data === 'string' ? JSON.parse(ollamaResponse.data) : ollamaResponse;
  responseText = parsed.response || parsed.data?.response || '';
} catch (e) {
  responseText = JSON.stringify(ollamaResponse);
}

// Try to extract JSON from the response
let results;
try {
  // Find JSON in the response
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    results = JSON.parse(jsonMatch[0]);
  } else {
    results = { raw_analysis: responseText };
  }
} catch (e) {
  results = { raw_analysis: responseText };
}

const inputData = $('Validate Input').first().json;

return [{
  json: {
    ...results,
    metadata: {
      texts_analyzed: inputData.count,
      model: 'llama3.1:8b',
      processed_at: new Date().toISOString()
    }
  }
}];
